(() => {
  const value = $json.data.created_time;

  if (!value) return '';

  const fixed = value.replace(/(\+|\-)(\d{2})(\d{2})$/, '$1$2:$3');

  const dt = DateTime.fromISO(fixed);

  if (!dt.isValid) return 'Fecha inválida';

  return dt
    .setZone('America/Argentina/Buenos_Aires')
    .toFormat('dd/LL/yyyy HH:mm:ss');
})()
}}

value.Teléfono:
={{
(() => {
  const raw =
    $json.telefono ??
    $json.phone ??
    $json.data?.field_data?.phone ??
    $json.data?.field_data?.phone_number ??
    '';

  let d = String(raw).replace(/\D/g, '');

  // Normalizaciones típicas AR
  if (d.startsWith('549')) d = d.slice(3);
  else if (d.startsWith('54')) d = d.slice(2);
  if (d.startsWith('0')) d = d.slice(1);

  // Si viene con 15 (muchos formularios)
  if (d.startsWith('15') && d.length > 10) d = d.slice(2);

  return d;
})()
}}

