for (const item of $input.all()) {
  if (item.json.message.includes('concordia_design')) item.json.properties = [6868436];

  if (item.json.message.includes('helguera_park')) item.json.properties = [6868349];

  if (item.json.message.includes('campana_design')) item.json.properties = [6869016];

  if (item.json.message.includes('santo_tomé')) item.json.properties = [6869227];

}

return $input.all();

// 1. Obtenemos el estado de la última ejecución (es uno solo, usamos .first())
const state = $('Get last Lead timestamp & id').first().json;
const lastTimestamp = new Date(state.last_lead_time).getTime();
const lastLeadId = state.last_lead_id ? state.last_lead_id.toString() : null;

const newItems = [];

// 2. Recorremos cada entrada (cada entrada es un formulario con sus leads)
for (let i = 0; i < $input.all().length; i++) {
  const item = $input.all()[i];

  // --- CORRECCIÓN CRÍTICA ---
  // Usamos pairedItem() indicando el índice 'i' para que n8n busque 
  // la página y formulario que dieron origen a ESTE ítem específicamente.

  const pageData = $('Split Facebook Pages').pairedItem(i).json;
  const formData = $('Split con Page Data').pairedItem(i).json;

  const page_name = pageData.name;
  const page_id = pageData.id;
  const form_name = formData.name;
  const form_id = formData.id;

  const origin_key = `${page_name} | ${form_name}`;

  // Filtramos los leads
  const leads = (item.json.data || []).filter((lead) => {
    const created = new Date(lead.created_time).getTime();
    const id = lead.id;

    if (!Number.isFinite(created)) return false;

    if (created > lastTimestamp) return true;
    if (created === lastTimestamp && id !== lastLeadId) return true;

    return false;
  });

  if (leads.length > 0) {
    newItems.push({
      json: {
        page_name: page_name,
        page_id: page_id,
        form_name: form_name,
        form_id: form_id,
        origin_key: origin_key,
        origin: "Facebook",
        data: leads 
      }
    });
  }
}

return newItems;

const leads = $('Lead Master Processor').all();

let maxLead = null;

for (const item of leads) {

  const lead = item.json.data;

  if (!lead?.created_time) continue;

  const leadDate = new Date(lead.created_time);

  if (!maxLead || leadDate > new Date(maxLead.created_time)) {
    maxLead = lead;
  }
}

// evitar duplicados en la próxima ejecución
let nextDate = null;

if (maxLead?.created_time) {
  nextDate = new Date(maxLead.created_time);
  nextDate.setSeconds(nextDate.getSeconds() + 1);
}

return [
  {
    json: {
      last_lead_time: nextDate ? nextDate.toISOString() : null,
      last_lead_id: maxLead?.id || null
    }
  }
];

// 1. OBTENCIÓN DE CONFIGURACIÓN DE AGENTES
const configNodes = $("Get sales representative target").all();
const configMap = {};

configNodes.forEach(node => {
  const data = node.json;
  configMap[data.Origen] = {
    agentes: data.Agentes ? data.Agentes.split(',').map(a => a.trim()).filter(a => a) : [],
    etiquetas: data.Etiquetas ? data.Etiquetas.split(',').map(e => e.trim()) : [],
    emprendimiento: data.Emprendimiento || "",
    propiedad: data.Propiedad || ""
  };
});

// 2. MEMORIA ESTÁTICA n8n
const workflowStaticData = $getWorkflowStaticData('global');

// 3. PRE-ORDENAMIENTO Y FILTRO DE DUPLICADOS
let items = $input.all();

// Ordenamos por fecha primero (ascendente)
items.sort((a, b) => {
  const timeA = new Date(a.json.data?.created_time || a.json.created_time).getTime();
  const timeB = new Date(b.json.data?.created_time || b.json.created_time).getTime();
  return timeA - timeB;
});

// Filtramos duplicados comparando el ID de Facebook
const seenIds = new Set();
const uniqueItems = items.filter(item => {
  const leadId = item.json.data?.id || item.json.id;
  if (seenIds.has(leadId)) {
    return false; // Es un duplicado, lo eliminamos
  }
  seenIds.add(leadId);
  return true; // Es nuevo, lo mantenemos
});

// 4. PROCESAMIENTO, NORMALIZACIÓN Y ASIGNACIÓN
return uniqueItems.map((item) => {
  const leadRaw = item.json;
  const originKey = leadRaw.origin_key;
  const config = configMap[originKey];

  // --- LÓGICA DE AGENTES ---
  let assignedAgent = "Sin Agente";
  if (config && config.agentes.length > 0) {
    const lastRep = workflowStaticData[originKey] || null;
    const lastIndex = config.agentes.indexOf(lastRep);
    const nextIndex = (lastIndex === -1) ? 0 : (lastIndex + 1) % config.agentes.length;
    assignedAgent = config.agentes[nextIndex];
    workflowStaticData[originKey] = assignedAgent;
  }

  // --- NORMALIZACIÓN (Objeto plano y campos raíz) ---
  const fieldArray = leadRaw.data?.field_data || [];
  const fieldData = {};
  for (const field of fieldArray) {
    fieldData[field.name] = field.values?.[0] || '';
  }

  const full_name = fieldData.full_name || fieldData["full name"] || fieldData.first_name || '';
  const email = fieldData.email || fieldData.e_mail || '';
  const company_name = fieldData.company_name || '';
  const phone = fieldData.phone || fieldData.phone_number || fieldData.telefono || '';

  const ignored = ["full_name", "full name", "telefono", "phone", "phone_number", "email", "company_name"];
  const parts = [];
  for (const key in fieldData) {
    if (!ignored.includes(key) && fieldData[key]) {
      parts.push(`${key}: ${fieldData[key]}`);
    }
  }
  const message = parts.join("; ");

  return {
    json: {
      ...leadRaw, 
      data: {
        ...leadRaw.data,
        field_data: fieldData
      },
      full_name,
      phone,
      email,
      company_name,
      message,
      agent_mail: assignedAgent,
      tags: config ? config.etiquetas : [],
      developments: config?.emprendimiento ? [config.emprendimiento] : [],
      properties: config?.propiedad ? [config.propiedad] : []
    }
  };
});

